{"file_text": "using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough\nMozzarella cheese\nFresh basil\nSan Marzano tomatoes\nOlive oil\nSalt", Steps = "1. Preheat oven to 475°F\n2. Roll out dough on floured surface\n3. Spread crushed tomatoes evenly\n4. Add torn mozzarella pieces\n5. Bake for 10-12 minutes\n6. Top with fresh basil and drizzle olive oil" },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs\nYogurt\nGaram masala\nTurmeric\nCumin\nCrushed tomatoes\nHeavy cream\nGarlic\nGinger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours\n2. Grill or broil chicken until charred\n3. Sauté garlic and ginger in oil\n4. Add crushed tomatoes and simmer 15 minutes\n5. Stir in cream and spices\n6. Add chicken pieces and simmer 10 minutes" },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa", Steps = "1. Brown ground beef in skillet\n2. Add taco seasoning and water, simmer 5 minutes\n3. Warm tortillas in dry pan\n4. Assemble tacos with meat and toppings" },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Thai", Ingredients = "Rice noodles\nShrimp or tofu\nEggs\nBean sprouts\nGreen onions\nPeanuts\nFish sauce\nTamarind paste\nLime", Steps = "1. Soak rice noodles in warm water 30 minutes\n2. Make sauce: mix fish sauce, tamarind, sugar\n3. Stir-fry shrimp/tofu, set aside\n4. Scramble eggs in wok\n5. Add drained noodles and sauce, toss\n6. Add protein back, top with peanuts and lime" },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract", Steps = "1. Melt chocolate and butter together\n2. Whisk eggs and sugar until fluffy\n3. Fold chocolate mixture into eggs\n4. Add flour and vanilla, fold gently\n5. Pour into greased ramekins\n6. Bake at 425°F for 12-14 minutes\n7. Invert onto plate and serve immediately" },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "American", Ingredients = "Romaine lettuce\nParmesan cheese\nCroutons\nCaesar dressing\nLemon juice\nGarlic\nAnchovy paste", Steps = "1. Wash and chop romaine lettuce\n2. Make dressing: whisk garlic, anchovy paste, lemon, olive oil\n3. Toss lettuce with dressing\n4. Top with shaved parmesan and croutons" },
        new Recipe { Id = 7, Title = "Sushi Rolls", Category = "Japanese", Ingredients = "Sushi rice\nNori sheets\nFresh salmon\nAvocado\nCucumber\nRice vinegar\nSoy sauce\nWasabi", Steps = "1. Cook sushi rice and season with rice vinegar\n2. Place nori on bamboo mat, spread rice evenly\n3. Lay fish, avocado, cucumber in a line\n4. Roll tightly using the mat\n5. Slice with wet knife into 8 pieces\n6. Serve with soy sauce and wasabi" },
        new Recipe { Id = 8, Title = "Tiramisu", Category = "Desserts", Ingredients = "Ladyfingers\nMascarpone cheese\nEspresso\nEggs\nSugar\nCocoa powder\nKahlua (optional)", Steps = "1. Brew espresso and let cool, add Kahlua if using\n2. Beat egg yolks with sugar until thick\n3. Fold in mascarpone\n4. Beat egg whites to stiff peaks, fold in\n5. Dip ladyfingers briefly in espresso\n6. Layer in dish: ladyfingers, cream, repeat\n7. Refrigerate 4+ hours, dust with cocoa" },
    };

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public void RateRecipe(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            recipe.TotalRatingPoints += stars;
            recipe.RatingCount++;
        }
    }
}
