@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>Welcome to RecipeShare</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2>Browse by Category</h2>

<div class="row">
    @foreach (var category in Categories)
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@category</h5>
                    <a href="recipes/@category" class="btn btn-primary">View Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories { get; set; } = [];

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }
}

arguments.file_text:
@page "/recipes"
@page "/recipes/{Category}"

<PageTitle>Recipes - @(Category ?? "All Categories")</PageTitle>

@if (string.IsNullOrEmpty(Category))
{
    <h1>All Categories</h1>
    <div class="list-group">
        @foreach (var cat in Categories)
        {
            <a href="recipes/@cat" class="list-group-item list-group-item-action">@cat</a>
        }
    </div>
}
else
{
    <h1>@Category Recipes</h1>
    <p><a href="recipes">← Back to all categories</a></p>

    @if (Recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in Recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="text-muted">
                                @if (recipe.RatingCount > 0)
                                {
                                    <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                                }
                                else
                                {
                                    <span>No ratings yet</span>
                                }
                            </p>
                            <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string? Category { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories { get; set; } = [];
    private IReadOnlyList<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Categories = RecipeService.GetCategories();
        Recipes = string.IsNullOrEmpty(Category)
            ? []
            : RecipeService.GetRecipesByCategory(Category);
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="recipes">← Browse recipes</a>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: <a href="recipes/@Recipe.Category">@Recipe.Category</a></p>

    <StarRating RecipeId="Recipe.Id" CurrentRating="Recipe.AverageRating" RatingCount="Recipe.RatingCount" />

