@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="recipes">← Browse recipes</a>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: <a href="recipes/@Recipe.Category">@Recipe.Category</a></p>

    <StarRating RecipeId="Recipe.Id" CurrentRating="Recipe.AverageRating" RatingCount="Recipe.RatingCount" />

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.' && char.IsDigit(text[0]))
                text = text[3..];
            else if (text.Length > 3 && text[2] == '.' && char.IsDigit(text[0]) && char.IsDigit(text[1]))
                text = text[4..];
            <li>@text.TrimStart()</li>
        }
    </ol>

    <p class="mt-4"><a href="recipes/@Recipe.Category">← Back to @Recipe.Category recipes</a></p>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

