toolArgs.file_text:
@rendermode InteractiveServer

<div class="my-3 p-3 border rounded">
    <h5>Rate this recipe</h5>
    <div class="d-flex align-items-center gap-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="btn btn-link p-0 fs-4 text-decoration-none"
                    @onclick="() => SubmitRating(star)"
                    title="Rate @star star(s)">
                @(star <= HoverStar ? "★" : "☆")
            </button>
        }
        <span class="ms-3 text-muted">
            @if (RatingCount > 0)
            {
                @($"⭐ {CurrentRating:F1} ({RatingCount} ratings)")
            }
            else
            {
                @("No ratings yet")
            }
        </span>
    </div>
    @if (Submitted)
    {
        <p class="text-success mt-2 mb-0">Thanks for rating!</p>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private int HoverStar { get; set; }
    private bool Submitted { get; set; }

    private void SubmitRating(int stars)
    {
        RecipeService.RateRecipe(RecipeId, stars);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        HoverStar = stars;
        Submitted = true;
    }
}

