toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<strong>@Model.Title</strong>" has been added.
        <a href="recipe/@NewRecipeId">View it here</a>.
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
                <option value="">-- Select a category --</option>
                <option value="American">American</option>
                <option value="Desserts">Desserts</option>
                <option value="Indian">Indian</option>
                <option value="Italian">Italian</option>
                <option value="Japanese">Japanese</option>
                <option value="Mexican">Mexican</option>
                <option value="Thai">Thai</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => Model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Model.Ingredients" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Model.Steps" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel Model { get; set; } = new();
    private bool SubmitSuccess { get; set; }
    private int NewRecipeId { get; set; }

    private void HandleSubmit()
    {
        var recipe = new RecipeShare.Models.Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Ingredients = Model.Ingredients,
            Steps = Model.Steps
        };
        RecipeService.AddRecipe(recipe);
        NewRecipeId = recipe.Id;
        SubmitSuccess = true;
    }

    private void Reset()
    {
        Model = new();
        SubmitSuccess = false;
    }

    public class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title cannot exceed 100 characters")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = string.Empty;
    }
}

